/**
 * Configuration Aggregator
 *
 * Pure function that transforms raw config data (files, settings, errors)
 * into a unified AggregatedConfig with scope annotations. No IO, no side effects.
 *
 * Driving port: aggregateConfig(rawConfig) -> AggregatedConfig
 */

import type {
  AgentParseResult,
  AggregatedConfig,
  CommandDefinition,
  ConfigScope,
  DocFile,
  EnvVarEntry,
  HookConfig,
  McpServerConfig,
  PluginInfo,
  ReadErrorInfo,
  RuleEntry,
  SettingsParseResult,
  SkillDefinition,
} from "./types";
import { parseAgentFile } from "./agentParser";
import { parseSettings } from "./settingsParser";
import { parseSkillFile } from "./skillParser";

// ---------------------------------------------------------------------------
// Input types -- raw data from filesystem reader
// ---------------------------------------------------------------------------

export interface FileEntry {
  readonly path: string;
  readonly content: string;
  readonly scope: ConfigScope;
  readonly source: string;
}

export interface RawPluginDetail {
  readonly name: string;
  readonly version: string;
  readonly description: string;
  readonly homepage: string;
  readonly installPath: string;
  readonly readme: string;
  readonly installedAt: string;
}

export interface RawClaudeConfig {
  readonly agents: readonly FileEntry[];
  readonly commands: readonly FileEntry[];
  readonly skills: readonly FileEntry[];
  readonly settings: FileEntry | null;
  readonly hooks: readonly FileEntry[];
  readonly rules: readonly FileEntry[];
  readonly claudeMdFiles: readonly FileEntry[];
  readonly installedPlugins: FileEntry | null;
  readonly pluginDetails: readonly RawPluginDetail[];
  readonly errors: readonly ReadErrorInfo[];
  readonly scope?: ConfigScope | "both";
}

// ---------------------------------------------------------------------------
// Filename extraction
// ---------------------------------------------------------------------------

function extractFilename(filePath: string): string {
  const segments = filePath.split(/[/\\]/);
  return segments[segments.length - 1];
}

// ---------------------------------------------------------------------------
// Agent aggregation
// ---------------------------------------------------------------------------

function aggregateAgents(agentFiles: readonly FileEntry[]): readonly AgentParseResult[] {
  return agentFiles.map(parseAgentEntry);
}

function parseAgentEntry(entry: FileEntry): AgentParseResult {
  const filename = extractFilename(entry.path);
  const result = parseAgentFile(filename, entry.content, entry.scope, entry.source);

  if (result.tag === "parsed") {
    return {
      tag: "parsed",
      agent: {
        ...result.agent,
        filePath: entry.path,
      },
    };
  }

  return {
    tag: "error",
    filePath: entry.path,
    message: result.message,
  };
}

// ---------------------------------------------------------------------------
// Command aggregation
// ---------------------------------------------------------------------------

function aggregateCommands(commandFiles: readonly FileEntry[]): readonly CommandDefinition[] {
  return commandFiles.map(parseCommandEntry);
}

function parseCommandEntry(entry: FileEntry): CommandDefinition {
  const filename = extractFilename(entry.path);
  const partial = parseSkillFile(filename, entry.content);

  return {
    ...partial,
    filePath: entry.path,
    scope: entry.scope,
    source: entry.source,
  };
}

// ---------------------------------------------------------------------------
// Skill aggregation
// ---------------------------------------------------------------------------

function aggregateSkills(skillFiles: readonly FileEntry[]): readonly SkillDefinition[] {
  return skillFiles.map(parseSkillEntry);
}

function parseSkillEntry(entry: FileEntry): SkillDefinition {
  const filename = extractFilename(entry.path);
  const partial = parseSkillFile(filename, entry.content);

  return {
    ...partial,
    filePath: entry.path,
    scope: entry.scope,
    source: entry.source,
  };
}

// ---------------------------------------------------------------------------
// Settings aggregation
// ---------------------------------------------------------------------------

interface ParsedSettings {
  readonly hooks: readonly HookConfig[];
  readonly mcpServers: readonly McpServerConfig[];
  readonly rules: readonly RuleEntry[];
  readonly plugins: readonly PluginInfo[];
  readonly envVars: readonly EnvVarEntry[];
}

const EMPTY_SETTINGS: ParsedSettings = {
  hooks: [],
  mcpServers: [],
  rules: [],
  plugins: [],
  envVars: [],
};

function aggregateSettings(settingsEntry: FileEntry | null): ParsedSettings {
  if (settingsEntry === null) {
    return EMPTY_SETTINGS;
  }

  const result: SettingsParseResult = parseSettings(settingsEntry.content, settingsEntry.scope);

  if (result.tag === "error") {
    return EMPTY_SETTINGS;
  }

  return {
    hooks: annotateFilePath(result.hooks, settingsEntry),
    mcpServers: annotateFilePath(result.mcpServers, settingsEntry),
    rules: annotateFilePath(result.rules, settingsEntry),
    plugins: annotateFilePath(result.plugins, settingsEntry),
    envVars: annotateFilePath(result.envVars, settingsEntry),
  };
}

function annotateFilePath<T extends { readonly filePath: string }>(
  items: readonly T[],
  entry: FileEntry,
): readonly T[] {
  return items.map((item) => ({
    ...item,
    filePath: entry.path,
  }));
}

// ---------------------------------------------------------------------------
// Doc file aggregation
// ---------------------------------------------------------------------------

function aggregateDocs(claudeMdFiles: readonly FileEntry[]): readonly DocFile[] {
  return claudeMdFiles.map(toDocFile);
}

function toDocFile(entry: FileEntry): DocFile {
  return {
    filePath: entry.path,
    content: entry.content,
    scope: entry.scope,
  };
}

// ---------------------------------------------------------------------------
// Hook file aggregation (plugin hooks from hooks.json files)
// ---------------------------------------------------------------------------

function aggregateHookFiles(hookFiles: readonly FileEntry[]): readonly HookConfig[] {
  const allHooks: HookConfig[] = [];

  for (const entry of hookFiles) {
    try {
      const parsed = JSON.parse(entry.content);
      const hooksObj = parsed.hooks ?? parsed;
      for (const [event, handlers] of Object.entries(hooksObj)) {
        if (!Array.isArray(handlers)) continue;
        for (const handler of handlers) {
          const h = handler as Record<string, unknown>;
          // Plugin hooks can have nested { hooks: [...], matcher } or flat { type, command/url }
          const hookItems = Array.isArray(h.hooks) ? h.hooks : [h];
          for (const item of hookItems) {
            const hi = item as Record<string, unknown>;
            allHooks.push({
              event,
              command: String(hi.command ?? hi.url ?? ""),
              matchers: h.matcher ? [String(h.matcher)] : [],
              rawConfig: handler,
              filePath: entry.path,
              scope: entry.scope as ConfigScope,
              source: entry.source,
            });
          }
        }
      }
    } catch {
      // Malformed JSON — skip silently
    }
  }

  return allHooks;
}

// ---------------------------------------------------------------------------
// Rule file aggregation (markdown rules from rules/*.md files)
// ---------------------------------------------------------------------------

function aggregateRuleFiles(ruleFiles: readonly FileEntry[]): readonly RuleEntry[] {
  return ruleFiles.map((entry) => ({
    text: entry.content,
    source: entry.source,
    filePath: entry.path,
    scope: entry.scope as ConfigScope,
  }));
}

// ---------------------------------------------------------------------------
// Installed plugins aggregation
// ---------------------------------------------------------------------------

function aggregateInstalledPlugins(
  entry: FileEntry | null,
  details: readonly RawPluginDetail[],
): readonly PluginInfo[] {
  if (entry === null) return [];

  // Build a lookup from plugin name to detail
  const detailMap = new Map<string, RawPluginDetail>();
  for (const d of details) {
    detailMap.set(d.name, d);
  }

  try {
    const parsed = JSON.parse(entry.content);
    const plugins = parsed.plugins ?? {};
    const result: PluginInfo[] = [];

    for (const [name, entries] of Object.entries(plugins)) {
      const arr = entries as Array<{ version?: string }>;
      if (arr.length > 0) {
        const detail = detailMap.get(name);
        result.push({
          name,
          version: String(arr[0].version ?? "unknown"),
          description: detail?.description ?? "",
          homepage: detail?.homepage ?? "",
          installPath: detail?.installPath ?? "",
          readme: detail?.readme ?? "",
          installedAt: detail?.installedAt ?? "",
          filePath: entry.path,
          scope: entry.scope as ConfigScope,
        });
      }
    }

    return result;
  } catch {
    return [];
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export function aggregateConfig(rawConfig: RawClaudeConfig): AggregatedConfig {
  const agents = aggregateAgents(rawConfig.agents);
  const commands = aggregateCommands(rawConfig.commands);
  const skills = aggregateSkills(rawConfig.skills ?? []);
  const settings = aggregateSettings(rawConfig.settings);
  const docs = aggregateDocs(rawConfig.claudeMdFiles);
  const errors = [...rawConfig.errors];

  // Merge hooks from settings.json + plugin hooks.json files
  const pluginHooks = aggregateHookFiles(rawConfig.hooks ?? []);
  const allHooks = [...settings.hooks, ...pluginHooks];

  // Merge rules from settings.json + plugin rules/*.md files
  const pluginRules = aggregateRuleFiles(rawConfig.rules ?? []);
  const allRules = [...settings.rules, ...pluginRules];

  // Plugins from installed_plugins.json, enriched with plugin details
  const installedPlugins = aggregateInstalledPlugins(
    rawConfig.installedPlugins ?? null,
    rawConfig.pluginDetails ?? [],
  );
  const allPlugins = [...settings.plugins, ...installedPlugins];

  return {
    agents,
    commands,
    skills,
    hooks: allHooks,
    mcpServers: settings.mcpServers,
    rules: allRules,
    plugins: allPlugins,
    envVars: settings.envVars,
    docs,
    errors,
  };
}

export type { AggregatedConfig, ReadErrorInfo };

tests/unit/plugins/norbert-config/domain.source:
/**
 * Unit tests: Configuration Aggregator
 *
 * Property-based tests for the aggregateConfig pure function.
 * Validates structural invariants: isolation, scope preservation,
 * and monotonic growth of output lists relative to input lists.
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import {
  aggregateConfig,
  type RawClaudeConfig,
  type FileEntry,
  type ReadErrorInfo,
} from "../../../../../src/plugins/norbert-config/domain/configAggregator";

// ---------------------------------------------------------------------------
// Generators
// ---------------------------------------------------------------------------

const scopeArb = fc.constantFrom("user" as const, "project" as const);

const validAgentContent = fc.record({
  model: fc.constantFrom("opus-4", "sonnet-4", "haiku-3"),
}).map(({ model }) => `---\nmodel: ${model}\n---\n\nAgent description.`);

const validCommandContent = fc.string({ minLength: 1, maxLength: 100 })
  .map((text) => `# Command\n\n${text}`);

const fileEntryArb = (contentArb: fc.Arbitrary<string>, pathPrefix: string): fc.Arbitrary<FileEntry> =>
  fc.tuple(
    fc.string({ minLength: 1, maxLength: 20, unit: "grapheme" }).filter((s) => /^[a-z0-9-]+$/.test(s)),
    contentArb,
    scopeArb,
  ).map(([name, content, scope]) => ({
    path: `${scope === "user" ? "~/.claude" : "./.claude"}/${pathPrefix}/${name}.md`,
    content,
    scope,
  }));

const agentFileEntryArb = fileEntryArb(validAgentContent, "agents");
const commandFileEntryArb = fileEntryArb(validCommandContent, "commands");

const readErrorArb: fc.Arbitrary<ReadErrorInfo> = fc.tuple(
  fc.string({ minLength: 1, maxLength: 30, unit: "grapheme" }).filter((s) => /^[a-z0-9-]+$/.test(s)),
  fc.constantFrom("Permission denied", "File not found", "IO error"),
  scopeArb,
).map(([name, error, scope]) => ({
  path: `${scope === "user" ? "~/.claude" : "./.claude"}/agents/${name}.md`,
  error,
  scope,
}));

// ---------------------------------------------------------------------------
// Properties
// ---------------------------------------------------------------------------

describe("configAggregator properties", () => {
  it("agents output length equals agents input length (per-file parsing, no filtering)", () => {
    fc.assert(
      fc.property(
        fc.array(agentFileEntryArb, { minLength: 0, maxLength: 5 }),
        (agents) => {
          const rawConfig: RawClaudeConfig = {
            agents,
            commands: [],
            skills: [],
            settings: null,
            claudeMdFiles: [],
            errors: [],
            scope: "both",
          };
          const result = aggregateConfig(rawConfig);
          expect(result.agents).toHaveLength(agents.length);
        },
      ),
    );
  });

  it("commands output length equals commands input length", () => {
    fc.assert(
      fc.property(
        fc.array(commandFileEntryArb, { minLength: 0, maxLength: 5 }),
        (commands) => {
          const rawConfig: RawClaudeConfig = {
            agents: [],
            commands,
            skills: [],
            settings: null,
            claudeMdFiles: [],
            errors: [],
            scope: "both",
          };
          const result = aggregateConfig(rawConfig);
          expect(result.commands).toHaveLength(commands.length);
        },
      ),
    );
  });

  it("read errors are passed through unchanged", () => {
    fc.assert(
      fc.property(
        fc.array(readErrorArb, { minLength: 0, maxLength: 5 }),
        (errors) => {
          const rawConfig: RawClaudeConfig = {
            agents: [],
            commands: [],
            skills: [],
            settings: null,
            claudeMdFiles: [],
            errors,
            scope: "both",
          };
          const result = aggregateConfig(rawConfig);
          expect(result.errors).toHaveLength(errors.length);
          for (let i = 0; i < errors.length; i++) {
            expect(result.errors[i].path).toBe(errors[i].path);
            expect(result.errors[i].error).toBe(errors[i].error);
            expect(result.errors[i].scope).toBe(errors[i].scope);
          }
        },
      ),
    );
  });

  it("null settings produces empty hooks, mcpServers, rules, plugins, envVars", () => {
    const rawConfig: RawClaudeConfig = {
      agents: [],
      commands: [],
      skills: [],
      settings: null,
      claudeMdFiles: [],
      errors: [],
      scope: "both",
    };
    const result = aggregateConfig(rawConfig);
    expect(result.hooks).toEqual([]);
    expect(result.mcpServers).toEqual([]);
    expect(result.rules).toEqual([]);
    expect(result.plugins).toEqual([]);
    expect(result.envVars).toEqual([]);
  });

  it("envVars from settings receive filePath annotation from FileEntry.path", () => {
    fc.assert(
      fc.property(
        fc.dictionary(
          fc.string({ minLength: 1, maxLength: 20 }).filter((s) => /^[A-Z_][A-Z0-9_]*$/.test(s)),
          fc.string({ maxLength: 50 }),
          { minKeys: 0, maxKeys: 10 },
        ),
        scopeArb,
        fc.constantFrom("~/.claude/settings.json", "./.claude/settings.json"),
        (envBlock, scope, settingsPath) => {
          const settingsJson = JSON.stringify({ env: envBlock });
          const rawConfig: RawClaudeConfig = {
            agents: [],
            commands: [],
            skills: [],
            settings: { path: settingsPath, content: settingsJson, scope, source: scope },
            claudeMdFiles: [],
            errors: [],
            scope: "both",
          };
          const result = aggregateConfig(rawConfig);

          // envVars count matches input env block string entries
          const expectedCount = Object.values(envBlock).filter(
            (v) => typeof v === "string",
          ).length;
          expect(result.envVars).toHaveLength(expectedCount);

          // Every envVar has filePath set to the settings FileEntry.path
          for (const entry of result.envVars) {
            expect(entry.filePath).toBe(settingsPath);
          }
        },
      ),
      { numRuns: 100 },
    );
  });

  it("agent scope is preserved from FileEntry, not hardcoded", () => {
    fc.assert(
      fc.property(
        agentFileEntryArb,
        (agentEntry) => {
          const rawConfig: RawClaudeConfig = {
            agents: [agentEntry],
            commands: [],
            skills: [],
            settings: null,
            claudeMdFiles: [],
            errors: [],
            scope: "both",
          };
          const result = aggregateConfig(rawConfig);
          const agentResult = result.agents[0];
          if (agentResult.tag === "parsed") {
            expect(agentResult.agent.scope).toBe(agentEntry.scope);
          }
        },
      ),
    );
  });

  it("docs output length equals claudeMdFiles input length with scope preserved", () => {
    fc.assert(
      fc.property(
        fc.array(
          fc.tuple(
            fc.constantFrom("./CLAUDE.md", "~/.claude/CLAUDE.md"),
            fc.string({ minLength: 1, maxLength: 50 }),
            scopeArb,
          ).map(([path, content, scope]) => ({ path, content, scope })),
          { minLength: 0, maxLength: 3 },
        ),
        (claudeMdFiles) => {
          const rawConfig: RawClaudeConfig = {
            agents: [],
            commands: [],
            skills: [],
            settings: null,
            claudeMdFiles,
            errors: [],
            scope: "both",
          };
          const result = aggregateConfig(rawConfig);
          expect(result.docs).toHaveLength(claudeMdFiles.length);
          for (let i = 0; i < claudeMdFiles.length; i++) {
            expect(result.docs[i].filePath).toBe(claudeMdFiles[i].path);
            expect(result.docs[i].scope).toBe(claudeMdFiles[i].scope);
          }
        },
      ),
    );
  });
});

tests/acceptance/norbert-config/settings.source:
/**
 * Acceptance tests: Settings Parsing -- Hooks, MCP Servers, Rules, Plugins (US-003, US-004, US-005)
 *
 * Validates that settings.json is parsed into structured domain objects
 * for hooks, MCP servers, rules, and plugins. Covers happy paths,
 * missing sections, malformed JSON, and field validation.
 *
 * Driving ports: pure domain function (parseSettings)
 * These tests exercise the data transformation that feeds multiple tabs,
 * not the React rendering.
 *
 * Traces to: US-003, US-004, US-005 acceptance criteria
 */

import { describe, it, expect } from "vitest";
import {
  parseSettings,
  type SettingsParseResult,
} from "../../../src/plugins/norbert-config/domain/settingsParser";

// ---------------------------------------------------------------------------
// WALKING SKELETON
// ---------------------------------------------------------------------------

// @walking_skeleton
describe("User views hook bindings to verify configuration", () => {
  it("parses settings into structured hook definitions with event, command, and matchers", () => {
    // Given settings.json with 3 hook bindings configured
    const settingsJson = JSON.stringify({
      hooks: {
        PreToolUse: [
          {
            command: "/usr/local/bin/norbert-hook",
            matchers: ["Bash", "Write", "Edit", "MultiEdit"],
          },
        ],
        PostToolUse: [
          {
            command: "/usr/local/bin/norbert-hook",
            matchers: ["Bash", "Write", "Edit", "MultiEdit"],
          },
        ],
        Notification: [
          {
            command: "/usr/local/bin/norbert-hook",
          },
        ],
      },
    });

    // When settings are parsed
    const result = parseSettings(settingsJson);

    // Then parsing succeeds
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    // And 3 hook bindings are extracted
    expect(result.hooks).toHaveLength(3);

    // And the PreToolUse hook shows the command and matchers
    const preToolUse = result.hooks.find((h) => h.event === "PreToolUse");
    expect(preToolUse).toBeDefined();
    expect(preToolUse!.command).toBe("/usr/local/bin/norbert-hook");
